import React, { useState } from 'react';

import {
  Table,
  TableHead,
  TableContainer,
  Paper,
  TableCell,
  TableRow,
  TableBody,
  Button,
  TablePagination,
  Chip,
  Checkbox,
  Stack,
} from '@mui/material';
import dayjs from 'dayjs';
import { PAIDTYPE_STATUS } from 'utils/constants';
import { PAID_STATUS } from 'utils/constants';
import IconButton from '@mui/material/IconButton';
import DeleteIcon from '@mui/icons-material/Delete';
import ModeEditIcon from '@mui/icons-material/ModeEdit';
import LaunchIcon from '@mui/icons-material/Launch';

export default function ExpensesTableApplove({
  expenses,
  page,
  size,
  setPage,
  setSize,
  handleEdit,
  handleDelete,
  filter,
  handleApprove,
  handleSuccess,
  handleBillPickup,
  handleDetail,
  handleOpenPay,
  handleAddMultiPayment,
  selectedRows,
  setSelectedRows,
  handleReject,
  handleReset,
}) {
  const handleChangePage = (event, newPage) => {
    setPage(newPage + 1);
  };

  const handleChangeRowsPerPage = (event) => {
    setSize(event.target.value);
    setPage(1);
  };

  const checkColor = (e) => {
    if (e?.status === 'PENDING')
      return <Chip size="small" label="Pending" color="default" />;
    if (e?.status === 'APPROVE')
      return <Chip size="small" label="Approved" color="warning" />;
    if (e?.status === 'SUCCESS')
      return <Chip size="small" label="Success" color="success" />;
    if (e?.status === 'REJECT')
      return <Chip size="small" label="Rejected" color="error" />;
    if (e?.status === 'CANCEL')
      return (
        <Chip
          size="small"
          label="Cancelled"
          sx={{ backgroundColor: 'black', color: 'white' }}
        />
      );
  };

  const handleSelectRow = (data) => {
    setSelectedRows((prev) =>
      prev.some((row) => row?._id === data?._id)
        ? prev?.filter((rowId) => rowId !== data)
        : [...prev, data],
    );
  };

  const handleSelectAll = (event) => {
    if (event.target.checked) {
      const allIds = filter.filter((e) => e.status === 'APPROVE').map((e) => e);
      setSelectedRows(allIds);
    } else {
      setSelectedRows([]);
    }
  };

  return (
    <div>
      <Paper>
        <div className="p-2 flex justify-between items-center">
          <div className="flex items-center gap-2">
            <Checkbox
              checked={
                filter?.length > 0 &&
                filter?.filter((e) => e.status === 'APPROVE')?.length > 0 &&
                selectedRows?.length ===
                  filter?.filter((e) => e.status === 'APPROVE')?.length
              }
              indeterminate={
                selectedRows?.length > 0 &&
                selectedRows?.length <
                  filter?.filter((e) => e.status === 'APPROVE')?.length
              }
              onChange={handleSelectAll}
              size="small"
            />
            <div>เลือกทั้งหมด</div>
          </div>
          {selectedRows?.length !== 0 && (
            <div>
              <Button
                variant="contained"
                color="primary"
                disabled={selectedRows?.length === 0}
                onClick={() => handleAddMultiPayment(selectedRows)}
              >
                Add Payment (เลือก {selectedRows.length} รายการ)
              </Button>
            </div>
          )}
        </div>
        <TableContainer component={Paper}>
          <Table size="small">
            <TableHead>
              <TableRow className="bg-theme-600">
                <TableCell align="center"></TableCell>
                <TableCell align="center">
                  <h1 className="text-white">No.</h1>
                </TableCell>
                <TableCell align="center">
                  <h1 className="text-white">Date Created</h1>
                </TableCell>
                <TableCell align="center">
                  <h1 className="text-white">ID / Request Date</h1>
                </TableCell>
                <TableCell align="center">
                  <h1 className="text-white">Type</h1>
                </TableCell>
                <TableCell align="center">
                  <h1 className="text-white">Project</h1>
                </TableCell>

                <TableCell align="center">
                  <h1 className="text-white">Order</h1>
                </TableCell>
                <TableCell align="center">
                  <h1 className="text-white">Total</h1>
                </TableCell>
                <TableCell align="center">
                  <h1 className="text-white">Payee</h1>
                </TableCell>
                <TableCell align="center">
                  <h1 className="text-white">Applicant</h1>
                </TableCell>
                <TableCell align="center">
                  <h1 className="text-white">Actions</h1>
                </TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {_.isEmpty(filter) ? (
                <TableRow>
                  <TableCell colSpan={12} align="center">
                    No items
                  </TableCell>
                </TableRow>
              ) : (
                filter.map((e, index) => (
                  <TableRow key={e._id}>
                    <TableCell align="center">
                      <Checkbox
                        checked={selectedRows.some((row) => row._id === e._id)}
                        onChange={() => handleSelectRow(e)}
                        disabled={e.status !== 'APPROVE'}
                        size="small"
                      />
                    </TableCell>
                    <TableCell align="center">{index + 1}</TableCell>
                    <TableCell align="center">
                      <h1>{dayjs(e?.createdAt).format('DD/MM/YYYY')}</h1>
                      <h1>{checkColor(e)}</h1>
                    </TableCell>
                    <TableCell align="center">
                      <h1 className="font-bold text-theme-600">{e?.code}</h1>
                      <h1>{dayjs(e?.date).format('DD/MM/YYYY')}</h1>
                    </TableCell>
                    <TableCell align="center">
                      {e?.expenses_type === 'PAY' ? (
                        <Chip
                          size="small"
                          label="เบิกเพื่อจ่าย"
                          color="primary"
                        />
                      ) : e?.expenses_type === 'REFUND' ? (
                        <Chip size="small" label="เบิกคืน" color="secondary" />
                      ) : (
                        <Chip size="small" label="-" />
                      )}
                    </TableCell>
                    <TableCell>
                      <h1 className="font-bold">
                        {e?.project?.project_number || '-'}
                      </h1>
                      {/* <h1>{e?.project?.name || '-'}</h1> */}
                      <h1 className="font-bold">
                        {e?.budget?.prefix}
                        {e?.budget?.budget_number} {e?.budget?.name || '-'}
                      </h1>
                    </TableCell>

                    <TableCell>
                      <div className="flex">
                        <h1>{e?.name}</h1>
                        <IconButton
                          size="small"
                          onClick={() => handleDetail(e._id)}
                        >
                          <LaunchIcon fontSize="inherit" />
                        </IconButton>
                      </div>
                    </TableCell>
                    <TableCell align="center">
                      ฿
                      {e?.price
                        ?.toFixed(2)
                        ?.replace(/\d(?=(\d{3})+\.)/g, '$&,')}
                    </TableCell>
                    <TableCell>
                      <h1>
                        <b>Name: </b>
                        {e?.payee?.name || '-'}
                      </h1>
                      <h1>
                        <b>Bank: </b>
                        {e?.payee?.bank || '-'}
                      </h1>
                      <h1>
                        <b>Account: </b>
                        {e?.payee?.account_number || '-'}
                      </h1>
                    </TableCell>
                    <TableCell align="center">
                      {e?.employee?.firstname} {e?.employee?.lastname}
                    </TableCell>
                    <TableCell>
                      <div className="">
                        {e?.status === 'PENDING' && (
                          <Stack direction="column" spacing={1}>
                            <Button
                              variant="contained"
                              size="small"
                              onClick={() => handleApprove(e._id)}
                            >
                              Approve
                            </Button>
                            <Button
                              variant="contained"
                              size="small"
                              color="error"
                              onClick={() => handleReject(e._id)}
                            >
                              Reject
                            </Button>
                          </Stack>
                        )}
                        {e?.status === 'APPROVE' && (
                          <Button
                            variant="contained"
                            size="small"
                            color="success"
                            onClick={() => handleOpenPay(e)}
                          >
                            Add Payment
                          </Button>
                        )}

                        {e?.status === 'REJECT' && (
                          <Button
                            variant="contained"
                            size="small"
                            color="error"
                            onClick={() => handleReset(e._id)}
                          >
                            RESET
                          </Button>
                        )}
                        {e?.status === 'CANCEL' && (
                          <Button
                            variant="contained"
                            size="small"
                            onClick={() => handleReset(e._id)}
                          >
                            RESET
                          </Button>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </TableContainer>
        {/* ปุ่ม Add Payment หลายรายการ */}

        <TablePagination
          rowsPerPageOptions={[30, 70, 100, 500, 1000]}
          component="div"
          count={expenses?.total || 0}
          rowsPerPage={size}
          page={page - 1}
          onPageChange={handleChangePage}
          onRowsPerPageChange={handleChangeRowsPerPage}
        />
      </Paper>
    </div>
  );
}
